import time
from ag2 import GroupChatManager

class LatencyDetector:
    def __init__(self):
        self.speaker_latencies = []

    def select_speaker(self, last_speaker, states):
        start = time.perf_counter()
        speaker = self._auto_select(last_speaker, states)
        latency = time.perf_counter() - start
        if latency > 2.0:
            print(f'🚨 Speaker selection bottleneck: {latency:.2f}s')
        return speaker

manager = GroupChatManager(..., speaker_selection_method=LatencyDetector())

