from ag2 import GroupChat
from concurrent.futures import ThreadPoolExecutor

class FastGroupChat(GroupChat):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.prefetch_pool = ThreadPoolExecutor(max_workers=2)
        self.response_cache = {}

    def select_speaker(self, last_speaker):
        # Pre-generate next candidates
        futures = []
        for agent in self.agents[:2]:
            if agent != last_speaker:
                future = self.prefetch_pool.submit(agent.generate_reply, self.messages[-1])
                futures.append((agent, future))

        speaker = super().select_speaker(last_speaker)
        self.response_cache[speaker.name] = next(f.result() for a,f in futures if a==speaker)
        return speaker

from ag2 import UserProxyAgent
import tiktoken

class CompressedAgent(UserProxyAgent):
    def generate_reply(self, messages):
        # Compress to <8k tokens
        encoder = tiktoken.get_encoding('cl100k_base')
        compressed = self.compress_history(messages[-10:])

        if len(encoder.encode(str(compressed))) > 8000:
            compressed = self.messages[-4:]  # Last 4 exchanges

        return super().generate_reply(compressed)

    def compress_history(self, messages):
        return ' '.join([m['content'][-200:] for m in messages if 'content' in m])

proxy = CompressedAgent(name='user', max_consecutive_auto_reply=3)

