from ag2 import GroupChat, AssistantAgent
from vex_sdk import VexAgentMonitor

# Auto-instrument all AG2 agents
monitor = VexAgentMonitor(
    project='ag2-latency',
    thresholds={'llm_latency_p95': 2.5, 'token_rate_p10': 25}
)

# Agents auto-register with Vex
coder = AssistantAgent(
    name='coder',
    llm_config={'model': 'gpt-4o-mini'},
    vex_monitor=monitor  # Auto-hooks all messages
)

planner = AssistantAgent(name='planner', vex_monitor=monitor)

# Vex auto-fixes detected issues
groupchat = GroupChat(agents=[coder, planner], vex_monitor=monitor)

@monitor.on_latency_violation
def auto_optimize_llm(config):
    if config['model'] == 'gpt-4o':
        return {'model': 'gpt-4o-mini', 'quantization': '4bit'}
    return config

monitor.start()  # Begin automated monitoring/remediation
